# shapes_module.spy - Shape hierarchy using types from types_module
from types_module import IScalable, ShapeCategory, Point

@abstract
class Shape(IScalable):
    category: ShapeCategory
    center: Point

    def __init__(self, category: ShapeCategory, center: Point):
        self.category = category
        self.center = center

    @virtual
    def describe(self) -> str:
        return "Shape"

    @abstract
    def perimeter(self) -> float

class Circle(Shape):
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__(ShapeCategory.TWO_DIMENSIONAL, center)
        self.radius = radius

    @override
    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

    @override
    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return "Circle"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, center: Point, width: float, height: float):
        super().__init__(ShapeCategory.TWO_DIMENSIONAL, center)
        self.width = width
        self.height = height

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return "Rectangle"

