# utils_module.spy - Utility functions and helpers
from types_module import Point
from shapes_module import Shape, Circle, Rectangle

def format_number(n: float) -> str:
    # Format with 2 decimal places
    if n == int(n):
        return str(int(n)) + ".0"
    # Simple formatting - truncate to 2 decimals
    s: str = str(n)
    if "." in s:
        parts: list[str] = s.split(".")
        decimal: str = parts[1]
        if len(decimal) > 2:
            decimal = decimal[0:2]
        return parts[0] + "." + decimal
    return s + ".0"

class ShapeCollection:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add(self, shape: Shape):
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.get_area()
        return total

    def scale_all(self, factor: float):
        for shape in self.shapes:
            shape.scale(factor)
